import { useContext, useEffect, useMemo, useState } from "react";
import { AuthContext } from "./AuthContext";
import ClubHeader from "./ClubHeader";

import ClubOverview from "./tabs/ClubOverview";
import ClubMembers from "./tabs/ClubMembers";
import ClubNews from "./tabs/ClubNews";

export default function ClubPage() {
    const { user } = useContext(AuthContext);

    const clubId = (() => {
        const m = window.location.hash.match(/^#\/clubs\/(\d+)(?:\/(\w+))?/);
        return m ? Number(m[1]) : null;
    })();

    const activeTab = (() => {
        const m = window.location.hash.match(/^#\/clubs\/\d+\/(\w+)/);
        return m ? m[1] : "overview";
    })();

    const [club, setClub] = useState(null);
    const [news, setNews] = useState([]);
    const [members, setMembers] = useState([]);
    const [pending, setPending] = useState([]);
    const [users, setUsers] = useState([]);
    const [myStatus, setMyStatus] = useState({ isMember: false, hasPending: false });

    /* ---------- roles ---------- */
    const isAdmin = user?.role === "ADMIN";
    const isLeader = members.some(m => m.userId === user?.id && m.role === "LEADER");
    const isCoLeader = members.some(m => m.userId === user?.id && m.role === "CO_LEADER");

    const canPostNews = isAdmin || isLeader || isCoLeader;
    const canApprove = isAdmin || isLeader;

    /* ---------- derived ---------- */
    const sortedMembers = useMemo(() => {
        const rank = r => r === "LEADER" ? 0 : r === "CO_LEADER" ? 1 : 2;
        return [...members].sort((a,b) => rank(a.role) - rank(b.role));
    }, [members]);

    const userMap = useMemo(() => {
        const m = new Map();
        users.forEach(u => m.set(u.id, u));
        return m;
    }, [users]);

    const userLabel = id => {
        const u = userMap.get(id);
        return u ? `${u.username} (${u.email})` : `User #${id}`;
    };

    /* ---------- load data ---------- */
    useEffect(() => {
        if (!clubId) return;

        Promise.all([
            fetch(`/api/clubs/${clubId}`).then(r => r.json()),
            fetch(`/api/clubs/${clubId}/news`).then(r => r.json()),
            fetch(`/api/clubs/${clubId}/members`).then(r => r.json()),
            fetch("/api/users").then(r => r.json()),
            user
                ? fetch(`/api/clubs/${clubId}/status?requesterEmail=${user.email}`).then(r => r.json())
                : Promise.resolve({ isMember:false, hasPending:false })
        ]).then(([c,n,m,u,s]) => {
            setClub(c);
            setNews(n || []);
            setMembers(m || []);
            setUsers(u || []);
            setMyStatus(s);
        });
    }, [clubId, user?.email]);

    if (!club) return <div style={{padding:20}}>Loading…</div>;

    /* ---------- TAB RENDER ---------- */
    let Content = null;

    if (activeTab === "overview") {
        Content = (
            <ClubOverview
                news={news}
                members={sortedMembers}
                pending={pending}
                user={user}
                userLabel={userLabel}
                canPostNews={canPostNews}
                canApprove={canApprove}
                setNews={setNews}
            />
        );
    }

    if (activeTab === "members") {
        Content = (
            <ClubMembers
                members={sortedMembers}
                user={user}
                userLabel={userLabel}
            />
        );
    }

    if (activeTab === "news") {
        Content = (
            <ClubNews
                news={news}
                canPost={canPostNews}
                setNews={setNews}
            />
        );
    }

    return (
        <div className="page">
            <ClubHeader
                club={club}
                activeTab={activeTab}
                membership={myStatus}
            />
            {Content}
        </div>
    );
}
